namespace ProductReviews.Services
{
    public interface IReviewSanitizer
    {
        string SanitizeReviewContent(string rawContent);
    }
}

// Services/ReviewSanitizer.cs
using System.Net;
using System.Text.RegularExpressions;

namespace ProductReviews.Services
{
    public class ReviewSanitizer : IReviewSanitizer
    {
        /// <summary>
        /// Sanitizes user-submitted review content.
        /// First HTML-encodes all content to neutralize any malicious markup,
        /// then selectively re-enables only safe formatting tags: <b>, <i>, <strong>, <em>.
        /// </summary>
        public string SanitizeReviewContent(string rawContent)
        {
            if (string.IsNullOrEmpty(rawContent))
                return string.Empty;

            // Step 1: HTML-encode everything to prevent XSS
            string encoded = WebUtility.HtmlEncode(rawContent);

            // Step 2: Selectively restore only allowed formatting tags
            // Allowed tags: <b>, </b>, <i>, </i>, <strong>, </strong>, <em>, </em>
            encoded = RestoreAllowedTag(encoded, "b");
            encoded = RestoreAllowedTag(encoded, "i");
            encoded = RestoreAllowedTag(encoded, "strong");
            encoded = RestoreAllowedTag(encoded, "em");

            // Step 3: Convert newlines to <br /> for display
            encoded = encoded.Replace("\r\n", "<br />").Replace("\n", "<br />");

            return encoded;
        }

        private string RestoreAllowedTag(string encoded, string tagName)
        {
            // Restore opening tag: &lt;tagName&gt; -> <tagName>
            string encodedOpen = $"&lt;{tagName}&gt;";
            string decodedOpen = $"<{tagName}>";
            encoded = Regex.Replace(encoded, Regex.Escape(encodedOpen), decodedOpen, RegexOptions.IgnoreCase);

            // Restore closing tag: &lt;/tagName&gt; -> </tagName>
            string encodedClose = $"&lt;/{tagName}&gt;";
            string decodedClose = $"</{tagName}>";
            encoded = Regex.Replace(encoded, Regex.Escape(encodedClose), decodedClose, RegexOptions.IgnoreCase);

            return encoded;
        }
    }
}

// Controllers/ProductController.cs
using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using ProductReviews.Data;
using ProductReviews.Models;
using ProductReviews.Services;

namespace ProductReviews.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;
        private readonly IReviewSanitizer _reviewSanitizer;

        public ProductController(ApplicationDbContext context, IReviewSanitizer reviewSanitizer)
        {
            _context = context;
            _reviewSanitizer = reviewSanitizer;
        }

        // GET: /Product/Details/5
        public async Task<IActionResult> Details(int? id)
        {
            if (id == null)
                return NotFound();

            var product = await _context.Products
                .Include(p => p.Reviews)
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null)
                return NotFound();

            var viewModel = new ProductViewModel
            {
                Product = product,
                Reviews = product.Reviews
                    .OrderByDescending(r => r.CreatedAt)
                    .Select(r => new ReviewViewModel
                    {
                        Id = r.Id,
                        AuthorName = System.Net.WebUtility.HtmlEncode(r.AuthorName),
                        SanitizedContentHtml = _reviewSanitizer.SanitizeReviewContent(r.Content),
                        Rating = r.Rating,
                        CreatedAt = r.CreatedAt.ToString("MMMM dd, yyyy")
                    })
                    .ToList()
            };

            return View(viewModel);
        }

        // GET: /Product/SubmitReview/5
        [HttpGet]
        public async Task<IActionResult> SubmitReview(int? productId)
        {
            if (productId == null)
                return NotFound();

            var product = await _context.Products.FindAsync(productId);
            if (product == null)
                return NotFound();

            ViewBag.ProductId = productId;
            ViewBag.ProductName = product.Name;
            return View();
        }

        // POST: /Product/SubmitReview
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> SubmitReview([Bind("ProductId,AuthorName,Content,Rating")] Review review)
        {
            if (ModelState.IsValid)
            {
                var product = await _context.Products.FindAsync(review.ProductId);
                if (product == null)
                    return NotFound();

                review.CreatedAt = DateTime.UtcNow;

                // Store raw content in database; sanitization happens at render time
                _context.Reviews.Add(review);
                await _context.SaveChangesAsync();

                return RedirectToAction(nameof(Details), new { id = review.ProductId });
            }

            ViewBag.ProductId = review.ProductId;
            return View(review);
        }
    }
}

// Views/Product/Details.cshtml
@model ProductReviews.Models.ProductViewModel
@{
    ViewData["Title"] = Model.Product.Name + " - Reviews";
}

<div class="container mt-4">
    <div class="row">
        <div class="col-md-8">
            <h1>@Model.Product.Name</h1>
            <p class="text-muted">@Model.Product.Description</p>
            <h4 class="text-success">@Model.Product.Price.ToString("C")</h4>
            <hr />

            <div class="d-flex justify-content-between align-items-center mb-3">
                <h2>Customer Reviews (@Model.Reviews.Count)</h2>
                <a asp-action="SubmitReview" asp-route-productId="@Model.Product.Id"
                   class="btn btn-primary">Write a Review</a>
            </div>

            @if (Model.Reviews.Any())
            {
                <p class="text-muted">
                    <em>Reviewers can use &lt;b&gt;bold&lt;/b&gt; and &lt;i&gt;italic&lt;/i&gt; formatting.</em>
                </p>

                @foreach (var review in Model.Reviews)
                {
                    <div class="card mb-3">
                        <div class="card-body">
                            <div class="d-flex justify-content-between">
                                <h5 class="card-title">
                                    @* AuthorName is already HTML-encoded in the controller *@
                                    @Html.Raw(review.AuthorName)
                                </h5>
                                <small class="text-muted">@review.CreatedAt</small>
                            </div>
                            <div class="mb-2">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    if (i <= review.Rating)
                                    {
                                        <span class="text-warning">&#9733;</span>
                                    }
                                    else
                                    {
                                        <span class="text-muted">&#9734;</span>
                                    }
                                }
                            </div>
                            <div class="card-text review-content">
                                @* 
                                    SanitizedContentHtml has been sanitized by ReviewSanitizer:
                                    - All content is HTML-encoded first
                                    - Only safe tags (b, i, strong, em) are restored
                                    - Html.Raw is safe here because sanitization already occurred
                                *@
                                @Html.Raw(review.SanitizedContentHtml)
                            </div>
                        </div>
                    </div>
                }
            }
            else
            {
                <div class="alert alert-info">
                    No reviews yet. Be the first to review this product!
                </div>
            }
        </div>
    </div>
</div>

// Views/Product/SubmitReview.cshtml
@model ProductReviews.Models.Review
@{
    ViewData["Title"] = "Write a Review";
}

<div class="container mt-4">
    <div class="row">
        <div class="col-md-6">
            <h2>Write a Review for @ViewBag.ProductName</h2>
            <p class="text-muted">
                You can use basic formatting: <code>&lt;b&gt;bold&lt;/b&gt;</code>,
                <code>&lt;i&gt;italic&lt;/i&gt;</code>,
                <code>&lt;strong&gt;strong&lt;/strong&gt;</code>,
                <code>&lt;em&gt;emphasis&lt;/em&gt;</code>
            </p>
            <hr />

            <form asp-action="SubmitReview" method="post">
                @Html.AntiForgeryToken()
                <input type="hidden" name="ProductId" value="@ViewBag.ProductId" />

                <div asp-validation-summary="ModelOnly" class="text-danger"></div>

                <div class="form-group mb-3">
                    <label asp-for="AuthorName" class="form-label">Your Name</label>
                    <input asp-for="AuthorName" class="form-control" placeholder="Enter your name" />
                    <span asp-validation-for="AuthorName" class="text-danger"></span>
                </div>

                <div class="form-group mb-3">
                    <label asp-for="Rating" class="form-label">Rating</label>
                    <select asp-for="Rating" class="form-select">
                        <option value="">Select a rating</option>
                        <option value="5">★★★★★ (5 - Excellent)</option>
                        <option value="4">★★★★☆ (4 - Good)</option>
                        <option value="3">★★★☆☆ (3 - Average)</option>
                        <option value="2">★★☆☆☆ (2 - Poor)</option>
                        <option value="1">★☆☆☆☆ (1 - Terrible)</option>
                    </select>
                    <span asp-validation-for="Rating" class="text-danger"></span>
                </div>

                <div class="form-group mb-3">
                    <label asp-for="Content" class="form-label">Your Review</label>
                    <textarea asp-for="Content" class="form-control" rows="6"
                              placeholder="Write your review here. You can use <b>bold</b> and <i>italic</i> tags."></textarea>
                    <span asp-validation-for="Content" class="text-danger"></span>
                </div>

                <button type="submit" class="btn btn-primary">Submit Review</button>
                <a asp-action="Details" asp-route-id="@ViewBag.ProductId"
                   class="btn btn-secondary">Cancel</a>
            </form>
        </div>
    </div>
</div>

